import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { returnsService } from '../services/returns';
import {
  Card, StatusBadge, MLScorePanel, LoadingScreen, Alert, Button,
} from '../components/UI';
import { formatDate, formatReason, getRiskColor, getErrorMessage } from '../utils/helpers';
import {
  ArrowLeft, User, Package, Calendar, FileText,
  Brain, Image as ImageIcon, CheckCircle, XCircle,
  Clock, Flag, AlertTriangle, Info, ChevronDown, ChevronUp,
  ExternalLink, ShieldAlert,
} from 'lucide-react';

export default function ManagerReturnDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [actionLoading, setActionLoading] = useState('');
  const [actionSuccess, setActionSuccess] = useState('');
  const [lightbox, setLightbox] = useState(null);
  const [showRaw, setShowRaw] = useState(false);

  useEffect(() => {
    returnsService.getReturn(id)
      .then(r => setData(r.data))
      .catch(e => setError(getErrorMessage(e)))
      .finally(() => setLoading(false));
  }, [id]);

  const updateStatus = async (newStatus) => {
    setActionLoading(newStatus); setError(''); setActionSuccess('');
    try {
      const res = await returnsService.updateStatus(id, newStatus);
      setData(res.data);
      setActionSuccess(`Status updated to "${newStatus.replace('_', ' ')}"`);
      setTimeout(() => setActionSuccess(''), 3000);
    } catch (e) {
      setError(getErrorMessage(e));
    } finally {
      setActionLoading('');
    }
  };

  if (loading) return <LoadingScreen />;
  if (!data) return <div className="p-8 text-center text-slate-400">Return request not found.</div>;

  const risk = getRiskColor(data.risk_score);

  return (
    <div className="max-w-5xl mx-auto px-4 py-8 animate-fade-in">
      {/* Header */}
      <div className="flex items-center gap-3 mb-6">
        <Button variant="ghost" size="sm" icon={ArrowLeft} onClick={() => navigate(-1)}>Back</Button>
        <div className="flex-1">
          <h1 className="font-display text-xl font-bold text-slate-900">Return Request #{data.id}</h1>
          <p className="text-xs text-slate-400">
            Submitted {formatDate(data.created_at)} · Updated {formatDate(data.updated_at)}
          </p>
        </div>
        <StatusBadge status={data.status} />
      </div>

      {error && <Alert type="error" message={error} onClose={() => setError('')} className="mb-4" />}
      {actionSuccess && <Alert type="success" message={actionSuccess} className="mb-4" />}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-5">
        {/* Left column */}
        <div className="lg:col-span-2 space-y-5">
          {/* Customer Info */}
          <Card className="p-5">
            <div className="flex items-center gap-2 mb-4">
              <User className="w-4 h-4 text-slate-400" />
              <h2 className="font-semibold text-slate-700 text-sm">Customer Information</h2>
            </div>
            <div className="flex items-center gap-3 p-3 bg-slate-50 rounded-xl">
              <div className="w-10 h-10 bg-brand-100 rounded-full flex items-center justify-center flex-shrink-0">
                <span className="font-bold text-brand-700 text-sm">
                  {data.customer?.name?.charAt(0).toUpperCase()}
                </span>
              </div>
              <div>
                <p className="font-semibold text-slate-900 text-sm">{data.customer?.name}</p>
                <p className="text-xs text-slate-500">{data.customer?.email}</p>
              </div>
              <div className="ml-auto text-xs text-slate-400">
                Member since {formatDate(data.customer?.created_at)}
              </div>
            </div>
          </Card>

          {/* Product Details */}
          <Card className="p-5">
            <div className="flex items-center gap-2 mb-4">
              <Package className="w-4 h-4 text-slate-400" />
              <h2 className="font-semibold text-slate-700 text-sm">Product Details</h2>
            </div>
            <div className="grid grid-cols-2 gap-4 mb-4">
              {[
                { label: 'Order ID', value: `#${data.order_id}`, mono: true },
                { label: 'Product Name', value: data.product_name },
                { label: 'Return Reason', value: formatReason(data.return_reason) },
                { label: 'Delivery Date', value: formatDate(data.delivery_date) },
              ].map(({ label, value, mono }) => (
                <div key={label}>
                  <p className="text-xs text-slate-400 mb-0.5">{label}</p>
                  <p className={`text-sm font-semibold text-slate-800 ${mono ? 'font-mono' : ''}`}>{value}</p>
                </div>
              ))}
            </div>
            <div className="pt-4 border-t border-slate-100">
              <div className="flex items-center gap-1.5 mb-2">
                <FileText className="w-3.5 h-3.5 text-slate-400" />
                <p className="text-xs font-semibold text-slate-500">Customer Description</p>
              </div>
              <p className="text-sm text-slate-700 leading-relaxed bg-slate-50 rounded-xl p-3">
                {data.description}
              </p>
            </div>
          </Card>

          {/* Images */}
          {data.images?.length > 0 ? (
            <Card className="p-5">
              <div className="flex items-center gap-2 mb-4">
                <ImageIcon className="w-4 h-4 text-slate-400" />
                <h2 className="font-semibold text-slate-700 text-sm">Product Images ({data.images.length})</h2>
              </div>
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                {data.images.map((img, i) => (
                  <div
                    key={img.id}
                    className="relative group rounded-xl overflow-hidden border border-slate-200 aspect-square bg-slate-50 cursor-pointer"
                    onClick={() => setLightbox(img.image_url)}
                  >
                    <img src={img.image_url} alt={`Product ${i + 1}`} className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                      <ExternalLink className="w-5 h-5 text-white" />
                    </div>
                    {/* Image analysis overlay */}
                    <div className="absolute bottom-0 inset-x-0 bg-gradient-to-t from-black/70 to-transparent px-2 py-1.5 opacity-0 group-hover:opacity-100 transition-opacity">
                      <p className="text-[9px] text-white font-mono">
                        Manip: {(img.manipulation_score * 100).toFixed(0)}%
                      </p>
                    </div>
                    {img.manipulation_score > 0.5 && (
                      <div className="absolute top-1.5 right-1.5 bg-red-500 text-white text-[9px] font-bold px-1.5 py-0.5 rounded-md">
                        ⚠ EDITED?
                      </div>
                    )}
                  </div>
                ))}
              </div>
              {/* Image metadata flags */}
              {data.images.some(i => i.metadata_flags?.length > 0) && (
                <div className="mt-3 p-3 bg-amber-50 border border-amber-100 rounded-xl">
                  <p className="text-xs font-bold text-amber-700 mb-1">Image Analysis Flags</p>
                  {data.images.flatMap(img =>
                    img.metadata_flags?.map((f, i) => (
                      <p key={i} className="text-xs text-amber-700">• {f}</p>
                    )) || []
                  )}
                </div>
              )}
            </Card>
          ) : (
            <Card className="p-5">
              <div className="flex items-center gap-3 text-slate-400">
                <AlertTriangle className="w-5 h-5 text-amber-500" />
                <div>
                  <p className="text-sm font-semibold text-slate-700">No Images Submitted</p>
                  <p className="text-xs text-slate-400">This increases the risk score significantly.</p>
                </div>
              </div>
            </Card>
          )}

          {/* Raw ML Analysis (toggle) */}
          <Card className="overflow-hidden">
            <button
              onClick={() => setShowRaw(!showRaw)}
              className="w-full flex items-center justify-between px-5 py-3.5 hover:bg-slate-50 transition-colors"
            >
              <div className="flex items-center gap-2">
                <Info className="w-4 h-4 text-slate-400" />
                <span className="text-sm font-semibold text-slate-700">Raw ML Analysis Data</span>
              </div>
              {showRaw ? <ChevronUp className="w-4 h-4 text-slate-400" /> : <ChevronDown className="w-4 h-4 text-slate-400" />}
            </button>
            {showRaw && (
              <div className="px-5 pb-4 border-t border-slate-100">
                <pre className="mt-3 text-[10px] font-mono bg-slate-900 text-emerald-400 rounded-xl p-4 overflow-auto max-h-64">
                  {JSON.stringify(data.ml_analysis, null, 2)}
                </pre>
              </div>
            )}
          </Card>
        </div>

        {/* Right column — Risk Panel + Actions */}
        <div className="space-y-5">
          {/* Risk Overview */}
          <Card className="overflow-hidden">
            <div className={`px-5 py-4 ${risk.bg}`}>
              <div className="flex items-center gap-2 mb-1">
                <ShieldAlert className={`w-4 h-4 ${risk.text}`} />
                <span className={`text-xs font-bold ${risk.text} uppercase tracking-wide`}>
                  {risk.label} RISK
                </span>
              </div>
              <div className="flex items-end gap-2">
                <span className={`font-display text-4xl font-black ${risk.text}`}>
                  {Math.round(data.risk_score * 100)}
                </span>
                <span className={`text-lg font-bold ${risk.text} mb-0.5`}>/ 100</span>
              </div>
            </div>
            <div className="p-5">
              <div className="flex items-center gap-2 mb-4">
                <Brain className="w-4 h-4 text-indigo-500" />
                <h3 className="text-sm font-semibold text-slate-700">Score Breakdown</h3>
              </div>
              <MLScorePanel data={data} />
            </div>

            {data.risk_factors?.length > 0 && (
              <div className="px-5 pb-5">
                <div className="pt-4 border-t border-slate-100">
                  <div className="flex items-center gap-1.5 mb-2">
                    <AlertTriangle className="w-3.5 h-3.5 text-amber-500" />
                    <p className="text-xs font-bold text-slate-600">Risk Factors</p>
                  </div>
                  <ul className="space-y-1.5">
                    {data.risk_factors.map((f, i) => (
                      <li key={i} className="flex items-start gap-2">
                        <span className="text-amber-500 text-xs mt-0.5 flex-shrink-0">⚠</span>
                        <span className="text-xs text-slate-600 leading-relaxed">{f}</span>
                      </li>
                    ))}
                  </ul>
                </div>
              </div>
            )}
          </Card>

          {/* Manager Actions */}
          <Card className="p-5">
            <div className="flex items-center gap-2 mb-4">
              <Calendar className="w-4 h-4 text-slate-400" />
              <h3 className="text-sm font-semibold text-slate-700">Manager Actions</h3>
            </div>

            <div className="space-y-2.5">
              <Button
                variant="success"
                className="w-full"
                icon={CheckCircle}
                loading={actionLoading === 'approved'}
                disabled={data.status === 'approved'}
                onClick={() => updateStatus('approved')}
              >
                {data.status === 'approved' ? '✓ Approved' : 'Approve Request'}
              </Button>
              <Button
                variant="danger"
                className="w-full"
                icon={XCircle}
                loading={actionLoading === 'rejected'}
                disabled={data.status === 'rejected'}
                onClick={() => updateStatus('rejected')}
              >
                {data.status === 'rejected' ? '✓ Rejected' : 'Reject Request'}
              </Button>
              <Button
                variant="warning"
                className="w-full"
                icon={Clock}
                loading={actionLoading === 'under_review'}
                disabled={data.status === 'under_review'}
                onClick={() => updateStatus('under_review')}
              >
                Mark Under Review
              </Button>
              <Button
                variant="secondary"
                className="w-full border-purple-200 text-purple-700 hover:bg-purple-50"
                icon={Flag}
                loading={actionLoading === 'flagged'}
                disabled={data.status === 'flagged'}
                onClick={() => updateStatus('flagged')}
              >
                Flag as Suspicious
              </Button>
            </div>

            <div className="mt-4 pt-4 border-t border-slate-100">
              <p className="text-[10px] text-slate-400 text-center">
                Actions are logged and cannot be undone without authorization.
              </p>
            </div>
          </Card>

          {/* Model info */}
          <Card className="p-4">
            <p className="text-xs font-semibold text-slate-500 mb-2">Models Used</p>
            <div className="space-y-1">
              {Object.entries(data.ml_analysis?.model_versions || {}).map(([k, v]) => (
                <div key={k} className="flex justify-between text-[10px]">
                  <span className="text-slate-400 capitalize">{k.replace('_', ' ')}</span>
                  <span className="font-mono text-slate-600">{v}</span>
                </div>
              ))}
            </div>
          </Card>
        </div>
      </div>

      {/* Lightbox */}
      {lightbox && (
        <div
          className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center p-4"
          onClick={() => setLightbox(null)}
        >
          <img src={lightbox} alt="Full size" className="max-w-full max-h-full rounded-xl shadow-2xl" />
        </div>
      )}
    </div>
  );
}
